// Initial implementation
function setRememberMe(username, passwordHash) {
    const expires = new Date();
    expires.setTime(expires.getTime() + (30 * 24 * 60 * 60 * 1000));
    document.cookie = `remember_me=${username}:${passwordHash};expires=${expires.toUTCString()};path=/`;
}

function getRememberMe() {
    const cookies = document.cookie.split(';');
    for (let cookie of cookies) {
        cookie = cookie.trim();
        if (cookie.startsWith('remember_me=')) {
            return cookie.substring('remember_me='.length);
        }
    }
    return null;
}

function autoLogin() {
    const cookieData = getRememberMe();
    if (cookieData) {
        const [username, passwordHash] = cookieData.split(':');
        // Simulate login
        return { username, passwordHash };
    }
    return null;
}

